import{c as e,Q as r,j as o,m as s}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Claude Code 可客製化設計哲學 — @bcherny","description":"","frontmatter":{"title":"Claude Code 可客製化設計哲學 — @bcherny","author":"Boris Cherny（@bcherny）","date":"2026-02-11T00:00:00.000Z","source":"https://x.com/bcherny/status/2021699851499798911","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-02-11-@bcherny-798911.md","filePath":"research/tweets/2026-02-11-@bcherny-798911.md","lastUpdated":1779894392000}'),a={name:"research/tweets/2026-02-11-@bcherny-798911.md"};function n(l,t,d,i,h,c){return r(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="claude-code-可客製化設計哲學-—-bcherny" tabindex="-1">Claude Code 可客製化設計哲學 — @bcherny <a class="header-anchor" href="#claude-code-可客製化設計哲學-—-bcherny" aria-label="Permalink to &quot;Claude Code 可客製化設計哲學 — @bcherny&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/bcherny/status/2021699851499798911" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2021699851499798911</a><strong>作者</strong>：Boris Cherny（@bcherny） <strong>發布日期</strong>：2026-02-11 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文（Note Tweet） <strong>統計</strong>：4464 likes · 393 retweets · 7117 bookmarks · 588996 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Reflecting on what engineers love about Claude Code, one thing that jumps out is its customizability: hooks, plugins, LSPs, MCPs, skills, effort, custom agents, status lines, output styles, etc.</p><p>Every engineer uses their tools differently. We built Claude Code from the ground up to not just have great defaults, but to also be incredibly customizable. This is a reason why developers fall in love with the product, and why Claude Code&#39;s growth continues to accelerate.</p><p>I wanted to share a few ways we&#39;re seeing people and teams customize their Claudes.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 官方作者揭示可客製化性是產品核心競爭優勢，hooks/skills/MCP/agents 皆為設計意圖而非附加功能。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>可客製化性是首要設計目標</strong>：Claude Code 從零開始設計時就以「高度可客製化」為核心，而非只有良好預設值。</li><li><strong>客製化維度涵蓋完整工具鏈</strong>：hooks、plugins、LSPs、MCPs、skills、effort、custom agents、status lines、output styles 均屬設計意圖。</li><li><strong>差異化競爭優勢來源</strong>：可客製化性是開發者「愛上」產品的主因，也是成長加速的關鍵驅動力。</li><li><strong>每位工程師用法不同</strong>：官方認知到工程師工具使用習慣的個體差異，這是設計哲學的基礎前提。</li><li><strong>官方驗證生態系方向</strong>：作者宣告「分享人們和團隊客製化 Claude 的方式」，隱含對社群實踐的背書。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>列舉的客製化維度：hooks、plugins、LSPs、MCPs、skills、effort、custom agents、status lines、output styles</li><li>統計：588,996 views、7,117 bookmarks（高收藏比率，實用性信號強）</li><li>作者身份：Claude Code 官方負責人（@bcherny, Boris Cherny, Anthropic）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>宣言性大於操作性</strong>：此推文為高層哲學宣言，未提供具體技術細節或量化指標，對已熟悉 Claude Code 架構的工程師資訊密度有限。</li><li><strong>是起始推文</strong>：<code>is_note_tweet: true</code> 表示後續可能有展開說明，但 fxtwitter 未能展開 Note Tweet 完整內容；核心見解已在本文提取。</li><li><strong>cc-workspace 高度相關</strong>：此 workspace 的 CLAUDE.md 分層架構、hooks 設計、Skills 生態系皆是此設計哲學的直接實踐，提供官方設計意圖的一手確認。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>6/10</td><td>提供官方設計意圖背書，強化 hooks/skills/MCP 投資信心，但無新的操作步驟</td></tr><tr><td>B. 創新性 (20%)</td><td>4/10</td><td>對已熟悉 Claude Code 架構者無新觀點，屬於設計哲學確認而非新發現</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>作者身份本身即為第一手證據；無具體數字，但 7K+ bookmarks 顯示社群認同</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>高層宣言，無實作細節；技術內容預期在後續推文</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>設計哲學跨所有 Claude Code 使用者，不限特定技術棧</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.2/10</strong></td><td>A×0.3+B×0.2+C×0.2+D×0.15+E×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：此推文為官方設計哲學宣言，驗證既有 workspace 方向而無新增整合點；具體技術細節應在後續 Note Tweet 展開，若有後續推文 URL 可另行分析。</p><hr>',21)])])}const b=e(a,[["render",n]]);export{g as __pageData,b as default};
